import { useState, useEffect } from 'react';
import { getTasks, createTask, updateTask, deleteTask } from './services/api';

// 1. Fetching Tasks on Load
const loadTasks = async (currentFilter) => {
  try {
    setLoading(true);
    const result = await getTasks(currentFilter);
    // result is response.data from axios, which has our backend { success: true, data: [...] }
    setTasks(result.data); 
  } catch (err) {
    setError("Failed to fetch tasks from database.");
  } finally {
    setLoading(false);
  }
};

// 2. Handling Form Submit (Create)
const handleAddTask = async (formData) => {
  try {
    const result = await createTask(formData);
    // Append the newly created task from MongoDB directly to state
    setTasks(prev => [result.data, ...prev]);
  } catch (err) {
    alert("Error creating task: " + err.message);
  }
};

// 3. Handling Toggle Status / Edit
const handleUpdateTask = async (id, updatedData) => {
  try {
    const result = await updateTask(id, updatedData);
    // Notice we match on t._id now instead of t.id
    setTasks(prev => prev.map(t => t._id === id ? result.data : t));
  } catch (err) {
    alert("Error updating task");
  }
};

// 4. Handling Delete
const handleDeleteTask = async (id) => {
  if (window.confirm("Are you sure you want to delete this task?")) {
    try {
      await deleteTask(id);
      // Filter out using the MongoDB _id string key attribute
      setTasks(prev => prev.filter(t => t._id !== id));
    } catch (err) {
      alert("Error deleting task");
    }
  }
};
